    best_weighted_time = float('inf')

    for idx, customer_pos in enumerate(unvisited_customers):
        distance_to_customer = np.linalg.norm(customer_pos - cur_truck_pos)
        arrival_time = current_time + distance_to_customer / truck_speed

        if time_windows[idx][0] <= arrival_time <= time_windows[idx][1]:
            weighted_time = arrival_time * (1 + distance_to_customer)  # Weighted time calculation based on distance and arrival time
        elif arrival_time < time_windows[idx][0]:
            weighted_time = time_windows[idx][0] * (1 + distance_to_customer)
        else:
            weighted_time = arrival_time * (1 + distance_to_customer) + (arrival_time - time_windows[idx][1])  # Weighted time calculation with penalty

        if weighted_time < best_weighted_time:
